++      if (in == NULL || out == NULL || expt == NULL) {
++         Error2("select(%d): %s", max+1, strerror(errno));
++         if (in != NULL)
++               free(in);
++         if (out != NULL)
++               free(out);
++         if (expt != NULL)
++               free(expt);
++         return -1;
++      }
+       if (XIO_READABLE(xfd) && !(XIO_RDSTREAM(xfd)->eof >= 2 && !XIO_RDSTREAM(xfd)->ignoreeof)) {
+-	 FD_SET(XIO_GETRDFD(xfd), &in);
