+-		expt.__fds_bits[0], strerror(errno));
++		max+1, in->__fds_bits[0], out->__fds_bits[0],
++		expt->__fds_bits[0], strerror(errno));
+ #endif
++         free(in);
++         free(out);
++         free(expt);
+ 	 return -1;
+       } else if (retval == 0) {
+ 	 Info("terminated child did not leave data for us");
+@@ -679,6 +713,9 @@
+ 	 closing = MAX(closing, 1);
+       }
+    }
++   free(in);
++   free(out);
++   free(expt);
+    return 0;
