++                  free(in);
++                  free(out);
++                  free(expt);
+ 		  return 0;
+ 	       }
+ 	    }
+@@ -803,7 +863,9 @@
+ 
+       do {
+ 	 int _errno;
+-	 FD_ZERO(&in); FD_ZERO(&out); FD_ZERO(&expt);
++         memset(in, 0, howmany(max+1, NFDBITS) * FD_MASK_SIZE);
++         memset(out, 0, howmany(max+1, NFDBITS) * FD_MASK_SIZE);
