+ 
+ 	 childleftdata(sock1);
+ 	 childleftdata(sock2);
+@@ -819,23 +881,23 @@
+ 	     !(XIO_RDSTREAM(sock1)->eof > 1 && !XIO_RDSTREAM(sock1)->ignoreeof) &&
+ 	     !socat_opts.righttoleft) {
+ 	    if (!mayrd1) {
+-	       FD_SET(XIO_GETRDFD(sock1), &in);
