+       }
+-      if (XIO_GETWRFD(sock1) >= 0 && FD_ISSET(XIO_GETWRFD(sock1), &out)) {
++      if (XIO_GETWRFD(sock1) >= 0 && FD_ISSET(XIO_GETWRFD(sock1), out)) {
+ 	 maywr1 = true;
+       }
+-      if (XIO_GETWRFD(sock2) >= 0 && FD_ISSET(XIO_GETWRFD(sock2), &out)) {
++      if (XIO_GETWRFD(sock2) >= 0 && FD_ISSET(XIO_GETWRFD(sock2), out)) {
+ 	 maywr2 = true;
+       }
+ 
+@@ -989,6 +1057,10 @@
+    xioclose(sock1);
+    xioclose(sock2);
+ 
